}

func isPrime(x int64) bool {
	if x < 2 {
		return false
	}
	sqrtX := int64(math.Sqrt(float64(x)))
	for i := int64(2); i <= sqrtX; i++ {
		if x%i == 0 {
			return false
		}
	}
	return true
}

